<template><ModulePageShell title="月度质控报表" description="同一完整病例范围的分子、分母、状态和证据口径"><template #toolbar><a-space><a-range-picker v-model="months" mode="month" value-format="YYYY-MM"/><a-button type="primary" :loading="loading" @click="reload">拉取报表</a-button><a-button :disabled="!report" @click="exportCsv">导出CSV</a-button></a-space></template><a-alert v-if="error" type="error" show-icon>{{error}}</a-alert><a-empty v-else-if="!loading&&!report" description="请选择月份并拉取服务端报表"/><template v-for="period in report?.periods ?? []" :key="period.month"><a-card class="section-card" :bordered="false" :title="period.month"><a-table :data="period.indicators" row-key="code" :pagination="false"><a-table-column title="指标" data-index="name"/><a-table-column title="分子" data-index="numerator"/><a-table-column title="分母" data-index="denominator"/><a-table-column title="当前值" data-index="displayValue"/><a-table-column title="分母口径" data-index="denominatorDefinition"/><a-table-column title="证据"><template #cell="{record}">{{record.evidenceFields?.join('；')||'—'}}</template></a-table-column><a-table-column title="状态"><template #cell="{record}"><a-tag :color="record.status==='normal'?'green':record.status==='no-data'?'gray':'red'">{{record.status}}</a-tag></template></a-table-column></a-table></a-card></template></ModulePageShell></template>
<script setup lang="ts">import dayjs from'dayjs';import{onMounted,ref}from'vue';import ModulePageShell from'@/components/shared/ModulePageShell.vue';import{qualityApi,type QualityReportApi}from'@/api/quality';import{downloadTextFile}from'@/services/clinicalSync';const months=ref([dayjs().subtract(2,'month').format('YYYY-MM'),dayjs().format('YYYY-MM')]),report=ref<QualityReportApi|null>(null),loading=ref(false),error=ref('');async function reload(){loading.value=true;error.value='';try{report.value=await qualityApi.getReport({startMonth:months.value[0],endMonth:months.value[1]});}catch(e){report.value=null;error.value=`加载失败：${(e as Error).message}`;}finally{loading.value=false;}}function exportCsv(){if(!report.value)return;const rows=[['month','code','name','numerator','denominator','displayValue','status']];report.value.periods.forEach(p=>p.indicators.forEach(i=>rows.push([p.month,i.code,i.name,String(i.numerator),String(i.denominator),i.displayValue,i.status])));downloadTextFile(`quality-report-${months.value.join('-')}.csv`,rows.map(r=>r.map(v=>`"${v.split('"').join('""')}"`).join(',')).join('\n'));}onMounted(reload);</script>
